h2-step-2-accept-purchases-pf1ce984c.translation:
```swift
import Adapty

func purchaseProduct(_ product: AdaptyPaywallProduct) async {
    do {
        let purchaseResult = try await Adapty.makePurchase(product: product)

        switch purchaseResult {
        case .userCancelled:
            // El usuario canceló la compra
            break
        case .pending:
            // La compra está pendiente (p. ej., a la espera de aprobación parental)
            break
        case let .success(profile, transaction):
            // Compra exitosa, perfil actualizado
            break
        }
    } catch {
        // Gestionar el error
    }
}
```
